var e=JSON.parse(`[{"id":"L13_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"누, 누구야……!","JPN":"だ、誰……！","ENG":"W-who's there...?!","TWN":"誰，是誰……！"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어, 어라? 아무도 없잖아? 분명 무슨 소리가 들렸는데……?","JPN":"あ、あれ？　誰もいない？　確かに声が聞こえたのに……？","ENG":"H-huh? No one's here. But I'm sure I heard something...","TWN":"嗯？沒人嗎？我明明有聽到聲音……？"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래, 오늘은 무슨 일로 불렀나? 부사장?","JPN":"今日はどういった用件かね？　副社長？","ENG":"Oh, you wanted to see me, Vice President?","TWN":"說吧，副總找我有什麼事？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지난주 회의 때 이상한 보고가 하나 올라왔더군요.","JPN":"先週会議の際におかしな報告が一つあがっていました。","ENG":"Something odd was reported during last week's meeting.","TWN":"上週會議中有收到可疑的報告，"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님께서 확인해 주셔야 할 것 같습니다.","JPN":"社長にご確認いただきたいのですが。","ENG":"I think it's a matter you need to handle yourself, Boss.","TWN":"必須和老闆確認一下。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 중요한 내용인가?","JPN":"うん？　重要な内容なのか？","ENG":"Mm? Is it important?","TWN":"嗯？是什麼重要的內容嗎？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"일단은 괴담에 가까운 내용이었습니다.","JPN":"とりあえず怪談に近い内容だと言っておきましょう。","ENG":"The content of the report was closer to a ghost story.","TWN":"是類似都市傳說的內容。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"괴담?!","JPN":"怪談！？","ENG":"A ghost story?!","TWN":"都市傳說？！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 늦은 밤에 일을 하다 보면 회사 건물 옥상에서 음악 소리가 들려온다고 합니다.","JPN":"はい。夜遅くまで残って仕事をしていると、会社の屋上から演奏する音が聞こえてくるそうです。","ENG":"Yes. People have been hearing music coming from the rooftop when they are working late.","TWN":"是，聽說晚上在公司加班時，會從屋頂傳來音樂聲。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"레나 양이 확인하러 갔을 때는 문을 열자마자 음악이 뚝 끊기고 옥상은 텅 비어 있었다더군요.","JPN":"レナさんが確認しに行った時は、ドアを開けると演奏が止まり、屋上には誰もいなかったそうです。","ENG":"Lena went to investigate, but as soon as she opened the door, the music stopped and the rooftop was seemingly empty.","TWN":"蕾娜去確認的時候，門一打開音樂就停了，屋頂上也空蕩蕩的。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"화단을 일일이 들춰 봤는데 아무 흔적도 못 찾았다고 합니다.","JPN":"花壇を片っ端から確認しても、なんの痕跡もなかったとのことです。","ENG":"She searched every corner of the garden but couldn't find any traces.","TWN":"她把花圃都翻遍了，但什麼也沒發現。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"……호러물 시즌이라기엔 아직 이르지 않나?","JPN":"……まだ怪談の季節ではないと思うが？","ENG":"...Isn't it a bit early for horror season?","TWN":"……應該還沒到七月半吧？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님도 모르는 사람들에게는 충분히 괴담처럼 보일 수 있는 분입니다.","JPN":"お言葉ですが、社長も知らない人にとっては十分怪談の類に見えます。","ENG":"For people who don't know you, you can also be mistaken for a ghost story too, Boss.","TWN":"對某些不認識老闆的人而言，你長得也很七月半。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"경미한 침식 현상일 가능성도 배제할 수는 없지만……","JPN":"軽微な侵食現象である可能性も排除はできませんが……","ENG":"We cannot exclude the possibility that it could be a minor Counterside Effect...","TWN":"雖然也有可能是輕度侵蝕現象……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"멋대로 우리 회사 이름을 팔아 옥상을 정원으로 만든 녀석 소행이 아닐까 싶어서 말이죠.","JPN":"勝手にわが社の名前を使って屋上を庭園にした者の仕業ではないかと思いまして。","ENG":"But I'm guessing it is the doing of the one who sold our company name and made the rooftop into a garden.","TWN":"不過我想來想去，最有可能就是擅自冒用公司名義把屋頂變成花園的那個人吧？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠, 흠…….","JPN":"コホン、コホン……","ENG":"A-ahem! Hmm...","TWN":"咳咳……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"알겠네. 일단은 밤이 되길 기다려 봄세.","JPN":"承知した。とりあえず夜になるまで待ってみよう。","ENG":"Very well. I'll wait until this evening to check it out.","TWN":"我知道了，總之就先等到天黑再說吧。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};